import React, { useState, useEffect } from "react";
import axios from "axios";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [productoActual, setProductoActual] = useState({
    ProductoID: null,
    Nombre: "",
    Descripcion: "",
    Precio: "",
    Stock: "",
    CategoriaID: "",
    Imagen: null,
  });
  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");

  // Imagen modal
  const [imagenModal, setImagenModal] = useState(null);
  const [animarModal, setAnimarModal] = useState(false);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 7;

  useEffect(() => {
    obtenerProductos();
    obtenerCategorias();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (error) {
      console.error("❌ Error al obtener productos:", error);
    }
  };

  const obtenerCategorias = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/categorias");
      setCategorias(res.data);
    } catch (error) {
      console.error("❌ Error al obtener categorías:", error);
    }
  };

  const handleChange = (e) => {
    setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setProductoActual({ ...productoActual, Imagen: e.target.files[0] });
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      ProductoID: null,
      Nombre: "",
      Descripcion: "",
      Precio: "",
      Stock: "",
      CategoriaID: "",
      Imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };

  const abrirModalEditar = (producto) => {
    setProductoActual({
      ...producto,
      Imagen: null, // para subir nueva imagen opcional
    });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();
    try {
      const formData = new FormData();
      formData.append("Nombre", productoActual.Nombre);
      formData.append("Descripcion", productoActual.Descripcion);
      formData.append("Precio", productoActual.Precio);
      formData.append("Stock", productoActual.Stock);
      formData.append("categoria_id", productoActual.CategoriaID);
      if (productoActual.Imagen) formData.append("Imagen", productoActual.Imagen);

      if (modoEdicion) {
        await axios.put(
          `http://localhost:5000/api/productos/${productoActual.ProductoID}`,
          formData,
          { headers: { "Content-Type": "multipart/form-data" } }
        );
      } else {
        await axios.post("http://localhost:5000/api/productos", formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      }
      setShowModal(false);
      obtenerProductos();
    } catch (error) {
      console.error("❌ Error al guardar producto:", error);
    }
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Seguro que deseas eliminar este producto?")) {
      try {
        await axios.delete(`http://localhost:5000/api/productos/${id}`);
        obtenerProductos();
      } catch (error) {
        console.error("❌ Error al eliminar producto:", error);
      }
    }
  };

  const abrirImagenModal = (imagen) => {
    setImagenModal(imagen);
    setAnimarModal(true);
  };

  const cerrarImagenModal = () => {
    setAnimarModal(false);
    setTimeout(() => setImagenModal(null), 300);
  };

  // Filtrado
  const productosFiltrados = productos.filter((p) => {
    const nombre = p.Nombre ? p.Nombre.toLowerCase() : "";
    const descripcion = p.Descripcion ? p.Descripcion.toLowerCase() : "";
    return (
      nombre.includes(busqueda.toLowerCase()) ||
      descripcion.includes(busqueda.toLowerCase())
    );
  });

  // Paginación
  const totalPaginas = Math.ceil(productosFiltrados.length / productosPorPagina);
  const indiceInicio = (paginaActual - 1) * productosPorPagina;
  const indiceFin = indiceInicio + productosPorPagina;
  const productosPaginados = productosFiltrados.slice(indiceInicio, indiceFin);

  const cambiarPagina = (numero) => setPaginaActual(numero);

  return (
    <div className="container mt-5">
      {/* Buscador y botón agregar */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <input
          type="text"
          placeholder="Buscar producto por nombre o descripción..."
          className="form-control w-50"
          value={busqueda}
          onChange={(e) => {
            setBusqueda(e.target.value);
            setPaginaActual(1);
          }}
        />
        <button className="btn btn-success btn-lg" onClick={abrirModalAgregar}>
          ➕ Agregar Producto
        </button>
      </div>

      {/* Tabla */}
      <div className="table-responsive shadow-sm">
        <table className="table table-bordered text-center align-middle">
          <thead className="table-dark">
            <tr>
              <th>ID</th>
              <th>Imagen</th>
              <th>Nombre</th>
              <th>Descripción</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Categoría</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productosPaginados.map((p) => (
              <tr key={p.ProductoID}>
                <td>{p.ProductoID}</td>
                <td>
                  {p.Imagen ? (
                    <img
                      src={`http://localhost:5000/uploads/${p.Imagen}`}
                      alt={p.Nombre}
                      style={{ width: "70px", cursor: "pointer" }}
                      onClick={() => abrirImagenModal(p.Imagen)}
                    />
                  ) : (
                    "Sin imagen"
                  )}
                </td>
                <td>{p.Nombre}</td>
                <td>{p.Descripcion}</td>
                <td>${p.Precio}</td>
                <td>{p.Stock}</td>
                <td>{categorias.find((c) => c.CategoriaID === p.CategoriaID)?.Nombre || "Sin categoría"}</td>
                <td>
                  <button className="btn btn-warning btn-sm me-2" onClick={() => abrirModalEditar(p)}>✏️ Editar</button>
                  <button className="btn btn-danger btn-sm" onClick={() => eliminarProducto(p.ProductoID)}>🗑️ Eliminar</button>
                </td>
              </tr>
            ))}
            {productosPaginados.length === 0 && (
              <tr>
                <td colSpan="8" className="text-muted">No hay productos encontrados.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Paginador */}
      {totalPaginas > 1 && (
        <nav className="d-flex justify-content-center mt-4">
          <ul className="pagination">
            <li className={`page-item ${paginaActual === 1 ? "disabled" : ""}`}>
              <button className="page-link" onClick={() => cambiarPagina(paginaActual - 1)}>Anterior</button>
            </li>
            {Array.from({ length: totalPaginas }, (_, i) => (
              <li key={i} className={`page-item ${paginaActual === i + 1 ? "active" : ""}`}>
                <button className="page-link" onClick={() => cambiarPagina(i + 1)}>{i + 1}</button>
              </li>
            ))}
            <li className={`page-item ${paginaActual === totalPaginas ? "disabled" : ""}`}>
              <button className="page-link" onClick={() => cambiarPagina(paginaActual + 1)}>Siguiente</button>
            </li>
          </ul>
        </nav>
      )}

      {/* Modal Crear/Editar */}
      {showModal && (
        <div className="modal fade show" style={{ display: "block", backgroundColor: "rgba(0,0,0,0.6)" }}>
          <div className="modal-dialog modal-lg modal-dialog-centered">
            <div className="modal-content p-4 shadow-lg">
              <div className="modal-header">
                <h5 className="modal-title fw-bold">{modoEdicion ? "Editar Producto" : "Agregar Nuevo Producto"}</h5>
                <button type="button" className="btn-close" onClick={() => setShowModal(false)}></button>
              </div>
              <div className="modal-body">
                <form onSubmit={guardarProducto} encType="multipart/form-data">
                  <div className="row g-3">
                    <div className="col-md-6">
                      <label className="form-label">Nombre</label>
                      <input type="text" name="Nombre" value={productoActual.Nombre} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Precio</label>
                      <input type="number" step="0.01" name="Precio" value={productoActual.Precio} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-12">
                      <label className="form-label">Descripción</label>
                      <textarea name="Descripcion" value={productoActual.Descripcion} onChange={handleChange} className="form-control" rows="2"></textarea>
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Stock</label>
                      <input type="number" name="Stock" value={productoActual.Stock} onChange={handleChange} className="form-control" required />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label">Categoría</label>
                      <select name="CategoriaID" value={productoActual.CategoriaID || ""} onChange={handleChange} className="form-select" required>
                        <option value="">Seleccione una categoría</option>
                        {categorias.map((cat) => (
                          <option key={cat.CategoriaID} value={cat.CategoriaID}>{cat.Nombre}</option>
                        ))}
                      </select>
                    </div>
                    <div className="col-md-12">
                      <label className="form-label">Imagen</label>
                      <input type="file" accept="image/*" onChange={handleFileChange} className="form-control" />
                    </div>
                  </div>
                  <div className="mt-4 text-end">
                    <button type="button" className="btn btn-secondary me-2" onClick={() => setShowModal(false)}>Cancelar</button>
                    <button type="submit" className="btn btn-primary">{modoEdicion ? "Guardar Cambios" : "Guardar Producto"}</button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Imagen */}
      {imagenModal && (
        <div
          className="modal fade show"
          style={{
            display: "flex",
            justifyContent: "center",
            alignItems: "center",
            backgroundColor: "rgba(0,0,0,0.8)",
            position: "fixed",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%",
            zIndex: 1050,
            opacity: animarModal ? 1 : 0,
            transition: "opacity 0.3s",
          }}
          onClick={cerrarImagenModal}
        >
          <div
            className="modal-dialog"
            style={{
              maxWidth: "90%",
              pointerEvents: "none",
            }}
          >
            <div
              className="modal-content bg-transparent border-0"
              style={{
                pointerEvents: "auto",
                transform: animarModal ? "scale(1)" : "scale(0.7)",
                transition: "transform 0.3s",
              }}
            >
              <button
                onClick={cerrarImagenModal}
                style={{
                  position: "absolute",
                  top: "10px",
                  right: "10px",
                  background: "rgba(0,0,0,0.6)",
                  border: "none",
                  color: "#fff",
                  fontSize: "1.5rem",
                  borderRadius: "50%",
                  width: "40px",
                  height: "40px",
                  cursor: "pointer",
                }}
              >
                &times;
              </button>
              <img
                src={`http://localhost:5000/uploads/${imagenModal}`}
                alt="Producto"
                className="img-fluid"
                style={{ maxHeight: "80vh", margin: "auto", display: "block", borderRadius: "8px" }}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
